/*
 * asin() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly asin  (test_asin_opt.elf)
 *   2. Linked with toolchain's default asin       (test_asin_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += asin(vx);
#else
    double r = asin(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 hand-picked inputs for asin()         */
/* domain: [-1, 1]; outside is a domain error (NaN result)            */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf (domain error -> NaN) */
    emit_u(0xfff0000000000000ULL);  /* -Inf (domain error -> NaN) */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary and tiny normal values (6) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(1.0e-200);                 /* small normal well inside domain */
    emit(-1.0e-200);
    emit(1.0e-15);                  /* small but not tiny normal */

    /* --- Section 4: ULP neighbors of domain boundary +/-1.0 (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);                      /* exactly 1.0: asin(1) = pi/2 */
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 (domain error -> NaN) */
    emit_u(0x3fefffffffffffeULL);   /* a few ULPs below 1.0 */
    emit(-1.0);                     /* exactly -1.0: asin(-1) = -pi/2 */
    emit_u(0xbfefffffffffffffULL);  /* one ULP above -1.0 (toward zero) */
    emit_u(0xbff0000000000001ULL);  /* one ULP below -1.0 (domain error -> NaN) */
    emit_u(0xbfefffffffffffeULL);   /* a few ULPs above -1.0 (toward zero) */

    /* --- Section 5: Out-of-domain values (6) --- */
    emit(2.0);                      /* outside domain -> NaN */
    emit(-2.0);
    emit(1.5);
    emit(-1.5);
    emit(DBL_MAX);                  /* far outside domain -> NaN */
    emit(-DBL_MAX);

    /* --- Section 6: Key mathematical values (14) --- */
    /* asin(0.5) = pi/6, asin(sqrt(2)/2) = pi/4, asin(sqrt(3)/2) = pi/3 */
    emit(0.5);                      /* asin = pi/6 */
    emit(-0.5);
    emit_u(0x3fe6a09e667f3bcdULL);  /* sqrt(2)/2 ~ 0.70710678...: asin = pi/4 */
    emit_u(0xbfe6a09e667f3bcdULL);  /* -sqrt(2)/2 */
    emit_u(0x3febb67ae8584caaULL);  /* sqrt(3)/2 ~ 0.86602540...: asin = pi/3 */
    emit_u(0xbfebb67ae8584caaULL);  /* -sqrt(3)/2 */
    emit_u(0x3fdfa1c6c21f5c65ULL);  /* sin(pi/8) ~ 0.38268343...: asin = pi/8 */
    emit_u(0xbfdfa1c6c21f5c65ULL);  /* -sin(pi/8) */
    emit_u(0x3fe9ef51a1bf1950ULL);  /* sin(3pi/8) ~ 0.92387953...: asin = 3pi/8 */
    emit_u(0xbfe9ef51a1bf1950ULL);  /* -sin(3pi/8) */
    emit(0.1);                      /* small angle */
    emit(-0.1);
    emit(0.9);                      /* near boundary */
    emit(-0.9);

    /* --- Section 7: ULP neighbors around the |x|=0.5 polynomial transition (8) --- */
    emit_u(0x3fdffffffffffffeULL);  /* two ULPs below 0.5 */
    emit_u(0x3fdfffffffffffffULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000000ULL);  /* exactly 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0xbfdffffffffffffeULL);  /* two ULPs above -0.5 (toward zero) */
    emit_u(0xbfdfffffffffffffULL);  /* one ULP above -0.5 (toward zero) */
    emit_u(0xbfe0000000000000ULL);  /* exactly -0.5 */
    emit_u(0xbfe0000000000001ULL);  /* one ULP below -0.5 (away from zero) */

    /* --- Section 8: Uniform grid across (-1, 1) excluding already covered (15) --- */
    emit_u(0x3fc999999999999aULL);  /* ~0.1 */
    emit_u(0x3fd3333333333333ULL);  /* ~0.15 */
    emit_u(0x3fd999999999999aULL);  /* ~0.2 */
    emit_u(0x3fe0cccccccccccdULL);  /* ~0.525 */
    emit_u(0x3fe4000000000000ULL);  /* 0.625 */
    emit_u(0x3fe6666666666666ULL);  /* ~0.7 */
    emit_u(0x3fe999999999999aULL);  /* ~0.8 */
    emit_u(0x3fed70a3d70a3d71ULL);  /* ~0.925 */
    emit_u(0x3feeb851eb851eb8ULL);  /* ~0.96 */
    emit_u(0xbfc999999999999aULL);  /* ~-0.1 */
    emit_u(0xbfd3333333333333ULL);  /* ~-0.15 */
    emit_u(0xbfe0cccccccccccdULL);  /* ~-0.525 */
    emit_u(0xbfe6666666666666ULL);  /* ~-0.7 */
    emit_u(0xbfe999999999999aULL);  /* ~-0.8 */
    emit_u(0xbfed70a3d70a3d71ULL);  /* ~-0.925 */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* Many asin implementations use asin(x)~x below a small threshold */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 ~ 7.8e-3 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3fb0000000000000ULL);  /* 2^-4 = 0.0625 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-4 */
    emit_u(0x3f20000000000000ULL);  /* 2^-13 ~ 1.2e-4 */
    emit_u(0xbf20000000000000ULL);  /* -2^-13 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26 ~ 1.5e-8 */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */

    /* --- Section 10: Hard ULP cases near key result values (22) --- */
    /* Near asin result = pi/6 (input ~ 0.5) */
    emit_u(0x3fdfffffffffffeULL);   /* slightly below 0.5 */
    emit_u(0x3fe0000000000002ULL);  /* slightly above 0.5 */
    /* Near asin result = pi/4 (input ~ sqrt(2)/2) */
    emit_u(0x3fe6a09e667f3bccULL);  /* one ULP below sqrt(2)/2 */
    emit_u(0x3fe6a09e667f3bceULL);  /* one ULP above sqrt(2)/2 */
    /* Near asin result = pi/3 (input ~ sqrt(3)/2) */
    emit_u(0x3febb67ae8584ca9ULL);  /* one ULP below sqrt(3)/2 */
    emit_u(0x3febb67ae8584cabULL);  /* one ULP above sqrt(3)/2 */
    /* Near asin result = pi/2 (input near 1.0, maximum steepness) */
    emit_u(0x3feffffffffffeULL);    /* small epsilon below 1.0 */
    emit_u(0x3fefffffffffffc0ULL);  /* moderate epsilon below 1.0 */
    emit_u(0x3feffffffffffff0ULL);  /* tiny epsilon below 1.0 */
    emit_u(0xbfeffffffffffeULL);    /* small epsilon above -1.0 */
    /* Near-zero precise values */
    emit(0.25);
    emit(-0.25);
    emit(0.75);
    emit(-0.75);
    emit(0.3);
    emit(-0.3);
    emit(0.6);
    emit(-0.6);
    emit(0.95);
    emit(-0.95);
    emit(0.99);
    emit(-0.99);
}

#ifndef EN_PERF
/* ------------------------------------------------------------------ */
/* Dense sweep [-1, 1] in 200 steps                                   */
/* ------------------------------------------------------------------ */
static void test_sweep(void)
{
    int nsteps = 200;
    double step = 2.0 / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(-1.0 + (double)i * step);
}

/* Sample [0, 0.5] every 4503599627370496 ULP (~50 cases) */
static void test_exhaustive_small(void)
{
    uint64_t end = 0x3fe0000000000000ULL; /* 0.5 */
    for (uint64_t b = 0; b <= end; b += 4503599627370496ULL)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

